INSERT INTO bjcp_styles (id, code, name, category, og_min, og_max, fg_min, fg_max, ibu_min, ibu_max, srm_min, srm_max, abv_min, abv_max, sensory_description, sensory_description_es) VALUES
  ('american-light-lager', '1A', 'American Light Lager', 'Standard American Beer', 1.028, 1.040, 0.998, 1.008, 8, 12, 2, 3, 2.8, 4.2, 'A highly carbonated, very light-bodied, nearly flavorless lager designed to be consumed very cold. Very refreshing and thirst-quenching.', 'Una lager altamente carbonatada, de cuerpo muy ligero, casi sin sabor, diseñada para ser consumida muy fría. Muy refrescante e ideal para calmar la sed.'),
  ('american-lager', '1B', 'American Lager', 'Standard American Beer', 1.040, 1.050, 1.004, 1.010, 8, 18, 2, 3.5, 4.2, 5.3, 'A very pale, highly-carbonated, light-bodied, well-attenuated lager with a very neutral flavor profile and low bitterness. Served very cold, it can be a very refreshing and thirst-quenching drink.', 'Una lager muy pálida, altamente carbonatada, de cuerpo ligero y bien atenuada, con un perfil de sabor muy neutro y amargor bajo. Servida bien fría, puede ser una bebida muy refrescante e ideal para calmar la sed.'),
  ('cream-ale', '1C', 'Cream Ale', 'Standard American Beer', 1.042, 1.055, 1.006, 1.012, 8, 20, 2, 5, 4.2, 5.6, 'A clean, well-attenuated, highly carbonated, flavorful American "lawnmower" beer. Easily drinkable, smooth, and refreshing, with more character than typical American lagers, yet still subtle and restrained.', 'Una cerveza estadounidense limpia, bien atenuada, altamente carbonatada y con sabor, ideal para “tareas al aire libre”. Fácil de tomar, suave y refrescante, con más carácter que las típicas lagers estadounidenses, pero aun así sutil y discreta.'),
  ('american-wheat-beer', '1D', 'American Wheat Beer', 'Standard American Beer', 1.040, 1.055, 1.008, 1.013, 15, 30, 3, 6, 4.0, 5.5, 'A pale, refreshing grainy, doughy, or bready wheat beer with a clean fermentation profile and a variable hop character and bitterness. Its lighter body and higher carbonation contribute to its easy-drinking nature.', 'Una cerveza de trigo pálida y refrescante, con notas a grano, masa o pan, con un perfil de fermentación limpio, y carácter variable de lúpulo y amargor. Su cuerpo ligero y alta carbonatación contribuyen a que sea fácil de tomar.'),
  ('international-pale-lager', '2A', 'International Pale Lager', 'International Lager', 1.042, 1.050, 1.008, 1.012, 18, 25, 2, 6, 4.5, 6.0, 'A highly-attenuated pale lager without strong flavors, typically well-balanced and highly carbonated. Served cold, it is refreshing and thirst-quenching.', 'Una lager pálida altamente atenuada sin sabores fuertes, típicamente bien balanceada y altamente carbonatada. Servida fría, es refrescante e ideal para calmar la sed.'),
  ('international-amber-lager', '2B', 'International Amber Lager', 'International Lager', 1.042, 1.055, 1.008, 1.014, 8, 25, 6, 14, 4.5, 6.0, 'A smooth, easily-drinkable, malty amber lager with a flavorful caramel or toast character. Usually fairly well-attenuated, often with an adjunct quality and restrained bitterness.', 'Una lager ámbar maltosa, suave y fácil de tomar con un sabroso carácter a caramelo o a tostadas. Por lo general bastante bien atenuada, a menudo con un carácter de adjunto y un discreto amargor.'),
  ('international-dark-lager', '2C', 'International Dark Lager', 'International Lager', 1.044, 1.056, 1.008, 1.012, 8, 20, 14, 30, 4.2, 6.0, 'A darker, richer, and somewhat sweeter version of international pale lager with a little more body and flavor, but equally restrained in bitterness. The low bitterness leaves the malt as the primary flavor element, and the low hop levels provide very little in the way of balance.', 'Una versión más oscura, intensa y en cierta medida más dulce de una International Pale Lager con un poco más de cuerpo y sabor, pero igualmente discreta en amargor. El bajo amargor potencia a la malta como principal elemento de sabor, y los bajos niveles de lupulado aportan muy poco para balancear.'),
  ('czech-pale-lager', '3A', 'Czech Pale Lager', 'Czech Lager', 1.028, 1.044, 1.008, 1.014, 20, 35, 3, 6, 3.0, 4.1, 'A lighter-bodied, rich, refreshing, hoppy, bitter pale Czech lager having the familiar flavors of the stronger Czech Premium Pale Lager (Pilsner-type) beer but in a lower alcohol, lighter-bodied, and slightly less intense format.', 'Una lager checa pálida de cuerpo más ligero, sabrosa, refrescante, lupulada y amarga, que tiene los sabores familiares de la cerveza más fuerte Czech Premium Pale Lager (tipo Pilsner), pero en un formato con menos alcohol, cuerpo más ligero y levemente menos intensa.'),
  ('czech-premium-pale-lager', '3B', 'Czech Premium Pale Lager', 'Czech Lager', 1.044, 1.060, 1.013, 1.017, 30, 45, 3.5, 6, 4.2, 5.8, 'A refreshing pale Czech lager with considerable malt and hop character and a long finish. The malt flavors are complex for a Pilsner-type beer. The bitterness is strong and clean but lacks harshness, which gives a well-balanced, rounded flavor impression that enhances drinkability.', 'Una lager checa pálida y refrescante, con bastante carácter a malta y a lúpulo, y con un final prolongado. Los sabores a malta son complejos para una cerveza tipo Pilsner. El amargor es intenso y limpio pero sin asperezas, lo que aporta una impresión de balance y redondez en el sabor que realza la tomabilidad.'),
  ('czech-amber-lager', '3C', 'Czech Amber Lager', 'Czech Lager', 1.044, 1.060, 1.013, 1.017, 20, 35, 10, 16, 4.4, 5.8, 'A malty amber Czech lager with a hop character that can vary from low to quite significant. The malt flavors also can vary, leading to different interpretations and balances ranging from drier, bready, and slightly biscuity to sweeter and somewhat caramel-like.', 'Una lager checa ámbar de perfil maltoso, con un carácter de lúpulo que puede variar de bajo a bastante significativo. Los sabores de la malta también pueden variar, dando lugar a diferentes interpretaciones y balances que van desde las más secas, con notas a pan y un poco a galletas, hasta las más dulces y algo acarameladas.'),
  ('czech-dark-lager', '3D', 'Czech Dark Lager', 'Czech Lager', 1.044, 1.060, 1.013, 1.017, 18, 34, 17, 35, 4.4, 5.8, 'A rich, dark, malty Czech lager with a roast character that can vary from almost absent to quite prominent. Malty balance and an interesting and complex flavor profile, with variable levels of hopping that provides a range of possible interpretations.', 'Una lager checa sabrosa, oscura y maltosa con un carácter rostizado que puede ir desde casi ausente a bastante elevado. Balance hacia la malta y un perfil de sabor interesante y complejo, con diferentes niveles de lupulado que proporcionan una serie de posibles interpretaciones.'),
  ('munich-helles', '4A', 'Munich Helles', 'Pale Malty European Lager', 1.044, 1.048, 1.006, 1.012, 16, 22, 3, 5, 4.7, 5.4, 'A gold-colored German lager with a smooth, malty flavor and a soft, dry finish. Subtle spicy, floral, or herbal hops and restrained bitterness help keep the balance malty but not sweet, which helps make this beer a refreshing, everyday drink.', 'Una lager alemana de color dorado con un sabor maltoso suave y final seco sin asperezas. Lúpulos sutiles de carácter especiado, floral o herbáceo y un discreto amargor que ayuda a mantener el balance maltoso pero no dulce, lo que contribuye a hacer de esta cerveza una bebida refrescante para todos los días.'),
  ('festbier', '4B', 'Festbier', 'Pale Malty European Lager', 1.054, 1.057, 1.010, 1.012, 18, 25, 4, 6, 5.8, 6.3, 'A smooth, clean, pale German lager with a moderately strong malty flavor and a light hop character. Deftly balances strength and drinkability, with a palate impression and finish that encourages drinking. Showcases elegant German malt flavors without becoming too heavy or filling.', 'Una lager alemana pálida, suave y limpia, con sabor a malta moderadamente fuerte y un ligero carácter a lúpulo. Balancea con destreza la intensidad alcohólica y la tomabilidad, con una impresión en el paladar y un final que invitan a beber. Exhibe elegantes sabores a maltas alemanas sin llegar a ser demasiado pesada o llenar demasiado.'),
  ('helles-bock', '4C', 'Helles Bock', 'Pale Malty European Lager', 1.064, 1.072, 1.011, 1.018, 23, 35, 6, 9, 6.3, 7.4, 'A relatively pale, strong, malty German lager with a nicely attenuated finish that enhances drinkability. The hop character is generally more apparent and the malt character less deeply rich than in other Bocks.', 'Una lager alemana relativamente pálida, fuerte y maltosa, con un final bien atenuado que realza la tomabilidad. El carácter a lúpulo es generalmente más aparente, y la intensidad de malta es de una riqueza menos profunda que en otras Bock.'),
  ('german-leichtbier', '5A', 'German Leichtbier', 'Pale Bitter European Beer', 1.026, 1.034, 1.006, 1.010, 15, 28, 1.5, 4, 2.4, 3.6, 'A pale, highly-attenuated, light-bodied German lager with lower alcohol and calories than standard-strength beers. Moderately bitter with noticeable malt and hop flavors, the beer is still interesting to drink.', 'Una lager alemana pálida, altamente atenuada y de cuerpo ligero, con menos alcohol y calorías que las cervezas de intensidad estándar. Con un amargor moderado y sabores perceptibles de malta y lúpulo, esta cerveza resulta aún interesante de tomar.'),
  ('kolsch', '5B', 'Kolsch', 'Pale Bitter European Beer', 1.044, 1.050, 1.007, 1.011, 18, 30, 3.5, 5, 4.4, 5.2, 'A subtle, brilliantly clear, pale beer with a delicate balance of malt, fruit, and hop character, moderate bitterness, and a well-attenuated but soft finish. Freshness makes a huge difference with this beer, as the delicate character can fade quickly with age.', 'Una cerveza sutil, pálida y de claridad muy brillante, con un delicado balance entre el carácter a malta, la frutosidad y el lúpulo, con amargor moderado y un final bien atenuado pero suave. La frescura marca una gran diferencia en esta cerveza, ya que con el tiempo el carácter delicado puede desvanecerse rápidamente.'),
  ('german-helles-exportbier', '5C', 'German Helles Exportbier', 'Pale Bitter European Beer', 1.050, 1.058, 1.008, 1.015, 20, 30, 4, 6, 5.0, 6.0, 'A golden German lager balancing a smooth malty profile with a bitter, hoppy character in a slightly above-average body and strength beer.', 'Una lager alemana dorada que equilibra un suave perfil de malta con un carácter lupulado y amargo, en una cerveza de cuerpo e intensidad de alcohol levemente por encima del promedio.'),
  ('german-pils', '5D', 'German Pils', 'Pale Bitter European Beer', 1.044, 1.050, 1.008, 1.013, 22, 40, 2, 4, 4.4, 5.2, 'A pale, dry, bitter German lager featuring a prominent hop aroma. Crisp, clean, and refreshing, showing a brilliant gold color with excellent head retention.', 'Una lager alemana pálida, seca y amarga que presenta un prominente aroma a lúpulo. Crisp, limpia y refrescante, luciendo un color dorado brillante con excelente retención de espuma.'),
  ('marzen', '6A', 'Marzen', 'Amber Malty European Lager', 1.054, 1.060, 1.010, 1.014, 18, 24, 8, 17, 5.6, 6.3, 'An amber, malty German lager with a clean, rich, toasty, bready malt flavor, restrained bitterness, and a well-attenuated finish. The overall malt impression is soft, elegant, and complex, with a rich malty aftertaste that is never cloying or heavy.', 'Una lager alemana ámbar y maltosa, con un sabor a malta limpio, sabroso, tostado y similar al pan, con un discreto amargor y un final bien atenuado. La sensación general de la malta es suave, elegante y compleja, con un retrogusto sabroso y maltoso, que no es empalagoso ni pesado.'),
  ('rauchbier', '6B', 'Rauchbier', 'Amber Malty European Lager', 1.050, 1.057, 1.012, 1.016, 20, 30, 12, 22, 4.8, 6, 'A beechwood-smoked, malty, amber German lager. The expected Märzen profile of toasty-rich malt, restrained bitterness, clean fermentation, and a relatively dry finish is enhanced by a noticeable to intense smoke character.', 'Una lager alemana ámbar, maltosa y ahumada con madera de haya. El perfil esperado de una Märzen a malta tostada sabrosa, discreto amargor, fermentación limpia y un final relativamente seco, se realza con un carácter ahumado de notorio a intenso.'),
  ('dunkles-bock', '6C', 'Dunkles Bock', 'Amber Malty European Lager', 1.064, 1.072, 1.013, 1.019, 20, 27, 14, 22, 6.3, 7.2, 'A strong, dark, malty German lager beer that emphasizes the malty-rich and somewhat toasty qualities of continental malts without being sweet in the finish.', 'Una lager alemana fuerte, oscura y maltosa, que enfatiza las cualidades de rica maltosidad y un tanto tostadas de las maltas de Europa continental, sin presentar un final dulce.'),
  ('vienna-lager', '7A', 'Vienna Lager', 'Amber Bitter European Beer', 1.048, 1.055, 1.010, 1.014, 18, 30, 9, 15, 4.7, 5.5, 'A moderate-strength continental amber lager with a soft, smooth maltiness and a balanced, moderate bitterness, yet finishing relatively dry. The malt flavor is clean, bready-rich, and somewhat toasty, with an elegant impression derived from quality base malts and process, not specialty malts or adjuncts.', 'Una lager de Europa continental, de color ámbar e intensidad moderada, con una maltosidad suave y delicada, un amargor moderado y balanceado, y un final relativamente seco. El sabor a malta es limpio, con riqueza a pan y un perfil un tanto tostado. Da una impresión elegante que proviene de las maltas base y los procesos de calidad, y no de adjuntos o maltas especiales.'),
  ('altbier', '7B', 'Altbier', 'Amber Bitter European Beer', 1.044, 1.052, 1.008, 1.014, 25, 50, 9, 17, 4.3, 5.5, 'A moderately colored, well-attenuated, bitter beer with a rich maltiness balancing a strong bitterness. Light and spicy hop character complements the malt. A dry beer with a firm body and smooth palate.', 'Una cerveza de un color moderado, bien atenuada y amarga, con una riqueza de maltas que balancea el fuerte amargor. Un carácter de lúpulo ligero y especiado complementa la malta. Una cerveza seca con un cuerpo firme y paladar suave.'),
  ('munich-dunkel', '8A', 'Munich Dunkel', 'Dark European Lager', 1.048, 1.056, 1.010, 1.016, 18, 28, 17, 28, 4.5, 5.6, 'A traditional malty brown lager from Bavaria. Deeply toasted, bready malt flavors without any roasty or burnt flavors. Smooth and rich, with a restrained bitterness and a relatively dry finish that allows for drinking in quantity.', 'Una lager maltosa y marrón, tradicional de Baviera. Con sabores de malta profundamente tostados y a pan, sin un carácter rostizado ni quemado. Suave y sabrosa, con un discreto amargor y un final relativamente seco, que permite su consumo en gran cantidad.'),
  ('schwarzbier', '8B', 'Schwarzbier', 'Dark European Lager', 1.046, 1.052, 1.010, 1.016, 20, 35, 19, 30, 4.4, 5.4, 'A dark German lager that balances roasted yet smooth malt flavors with moderate hop bitterness. The lighter body, dryness, and lack of a harsh, burnt, or heavy aftertaste helps make this beer quite drinkable.', 'Una lager alemana oscura que balancea sabores rostizados pero suaves a malta, con un amargor de lúpulo moderado. El cuerpo más ligero, el final seco y la ausencia de un retrogusto áspero, quemado o pesado, la ayudan a ser bastante fácil de tomar.'),
  ('doppelbock', '9A', 'Doppelbock', 'Strong European Beer', 1.072, 1.112, 1.016, 1.024, 16, 26, 6, 25, 7.0, 10.0, 'A strong, rich, and very malty German lager that can have both pale and dark variants. The darker versions have more richly-developed, deeper malt flavors, while the paler versions have slightly more hops and dryness.', 'Una cerveza lager alemana, fuerte, rica y muy maltosa, que puede tener variedades pálidas y oscuras. Las versiones más oscuras presentan sabores a malta más profundos y complejos, mientras que las versiones más pálidas tienen un poco más de lúpulo y son más secas.'),
  ('eisbock', '9B', 'Eisbock', 'Strong European Beer', 1.078, 1.120, 1.020, 1.035, 25, 35, 17, 30, 9.0, 14.0, 'A strong, full-bodied, rich, and malty dark German lager often with a viscous quality and strong flavors. Even though flavors are concentrated, the alcohol should be smooth and warming, not burning.', 'Una lager alemana de color oscuro, fuerte, de cuerpo pleno, rica y maltosa, a menudo con un carácter viscoso y sabores intensos. Aunque los sabores están concentrados, el alcohol debe ser suave y cálido, no quemante.'),
  ('baltic-porter', '9C', 'Baltic Porter', 'Strong European Beer', 1.060, 1.090, 1.016, 1.024, 20, 40, 17, 30, 6.5, 9.5, 'A strong, dark, malty beer with different interpretations within the Baltic region. Smooth, warming, and richly malty, with complex dark fruit flavors and a roasted flavor without burnt notes.', 'Una cerveza fuerte, oscura y maltosa con diferentes interpretaciones dentro de la región Báltica. Suave, cálida y ricamente maltosa, con complejos sabores a frutas oscuras y un sabor rostizado sin notas quemadas.'),
  ('weissbier', '10A', 'Weissbier', 'German Wheat Beer', 1.044, 1.053, 1.008, 1.014, 8, 15, 2, 6, 4.3, 5.6, 'A pale, refreshing, lightly-hopped German wheat beer with high carbonation, dry finish, fluffy mouthfeel, and a distinctive banana-and-clove weizen yeast fermentation profile.', 'Una cerveza de trigo alemana pálida, refrescante, ligeramente lupulada, con alta carbonatación, final seco, sensación en boca esponjosa, y con un perfil de fermentación único que aporta un carácter a banana/plátano y clavo de olor.'),
  ('dunkles-weissbier', '10B', 'Dunkles Weissbier', 'German Wheat Beer', 1.044, 1.057, 1.008, 1.014, 10, 18, 14, 23, 4.3, 5.6, 'A moderately dark German wheat beer with a distinctive banana-and-clove weizen yeast fermentation profile, supported by a toasted bread or caramel malt flavor. Highly carbonated and refreshing, with a creamy, fluffy texture and light finish.', 'Una cerveza de trigo alemana moderadamente oscura con un distintivo carácter de levadura a banana/plátano y clavo de olor, sostenido por sabores de malta a pan tostado o caramelo. Altamente carbonatada y refrescante, con una textura cremosa y esponjosa, y un final ligero.'),
  ('weizenbock', '10C', 'Weizenbock', 'German Wheat Beer', 1.064, 1.090, 1.015, 1.022, 15, 30, 6, 25, 6.5, 9.0, 'A strong and malty German wheat beer combining the best wheat and yeast flavors of a Weissbier with the rich maltiness, strength, and body of a Bock. The style range includes Bock and Doppelbock strength, with variations for pale and dark color.', 'Una cerveza de trigo alemana fuerte y maltosa, que combina los mejores sabores del trigo y la levadura de una Weissbier, con la rica maltosidad, intensidad y cuerpo de una Bock. El rango del estilo incluye intensidades del tipo Bock y Doppelbock, con variantes de color pálido y oscuro.'),
  ('ordinary-bitter', '11A', 'Ordinary Bitter', 'British Bitter', 1.030, 1.039, 1.007, 1.011, 25, 35, 8, 14, 3.2, 3.8, 'Low gravity, alcohol, and carbonation make this an easy-drinking session beer. The malt profile can vary in flavor and intensity, but should never override the overall bitter impression. Drinkability is a critical component of the style.', 'Su baja densidad, nivel de alcohol y carbonatación hacen que esta sea una cerveza de sesión fácil de tomar. El perfil de malta puede variar en sabor e intensidad, pero nunca debe opacar la impresión de amargor general. La tomabilidad es un componente crítico de este estilo.'),
  ('best-bitter', '11B', 'Best Bitter', 'British Bitter', 1.040, 1.048, 1.008, 1.012, 25, 40, 8, 16, 3.8, 4.6, 'A flavorful, yet refreshing, session beer. Some examples can be more malt balanced, but this should not override the overall bitter impression. Drinkability is a critical component of the style.', 'Una cerveza de sesión sabrosa y refrescante. Algunos ejemplos pueden estar más balanceados a la malta, pero esta no debe opacar la impresión de amargor general. La tomabilidad es un componente crítico de este estilo.'),
  ('strong-bitter', '11C', 'Strong Bitter', 'British Bitter', 1.048, 1.060, 1.010, 1.016, 30, 50, 8, 18, 4.6, 6.2, 'An average-strength to moderately-strong British bitter ale. The balance may vary between fairly even between malt and hops to somewhat bitter. Drinkability is a critical component of the style. A rather broad style that allows for considerable interpretation by the brewer.', 'Una ale británica amarga con una intensidad de promedio a moderadamente fuerte. El balance puede variar desde bastante parejo entre malta y lúpulos a algo amargo. La tomabilidad es un componente crítico de este estilo. Es un estilo un tanto extenso que permite una interpretación amplia por quien elabora la cerveza.'),
  ('british-golden-ale', '12A', 'British Golden Ale', 'Pale Commonwealth Beer', 1.038, 1.053, 1.006, 1.012, 20, 45, 2, 5, 3.8, 5.0, 'A hop-forward, average-strength to moderately-strong pale bitter. Drinkability and a refreshing quality are critical components of the style, as it was initially a summer seasonal beer.', 'Cerveza pálida, amarga, balanceada hacia el lúpulo y de intensidad de media a moderadamente fuerte. La tomabilidad y una cualidad refrescante son componentes críticos del estilo, ya que inicialmente era una cerveza para la temporada de verano.'),
  ('australian-sparkling-ale', '12B', 'Australian Sparkling Ale', 'Pale Commonwealth Beer', 1.038, 1.050, 1.004, 1.006, 20, 35, 4, 7, 4.5, 6.0, 'A well-balanced, pale, highly carbonated, and refreshing ale suitable for drinking in a hot climate. Fairly bitter, with a moderate herbal-spicy hop and pome fruit ester profile. Smooth, neutral malt flavors with a fuller body but a crisp, highly-attenuated finish.', 'Una ale pálida, bien balanceada, muy carbonatada y refrescante, adecuada para tomar en climas cálidos. Bastante amarga, con un perfil moderado de lúpulo herbáceo y especiado, y ésteres a frutas pomáceas. Sabores de malta suaves y neutros, con un cuerpo más pleno pero un final crisp y muy atenuado.'),
  ('english-ipa', '12C', 'English IPA', 'Pale Commonwealth Beer', 1.050, 1.070, 1.010, 1.015, 40, 60, 6, 14, 5.0, 7.5, 'A bitter, moderately-strong, very well-attenuated pale British ale with a dry finish and a hoppy aroma and flavor. Classic British ingredients provide the most authentic flavor profile.', 'Una ale pálida británica, amarga, moderadamente fuerte, muy bien atenuada, con un final seco, y con aroma y sabor a lúpulo. Los ingredientes británicos clásicos proporcionan el perfil de sabor más auténtico.'),
  ('dark-mild', '13A', 'Dark Mild', 'Brown British Beer', 1.030, 1.038, 1.008, 1.013, 10, 25, 14, 25, 3.0, 3.8, 'A dark, low-gravity, malt-focused British session ale readily suited to drinking in quantity. Refreshing, yet flavorful for its strength, with a wide range of dark malt or dark sugar expression.', 'Una ale británica de sesión, oscura, de baja densidad, centrada en la malta, muy apropiada para tomar en cantidad. Refrescante, aunque sabrosa a pesar de su intensidad, con una amplia expresión de malta oscura o azúcar morena.'),
  ('british-brown-ale', '13B', 'British Brown Ale', 'Brown British Beer', 1.040, 1.052, 1.008, 1.013, 20, 30, 12, 22, 4.2, 5.9, 'A malty, caramelly, brown British ale without the roasted flavors of a Porter. Balanced and flavorful, but usually a little stronger than most average UK beers.', 'Una ale británica marrón, maltosa y acaramelada, sin los sabores rostizados de una porter. Balanceada y llena de sabor, pero por lo general un poco más fuerte que la mayoría de las cervezas promedio del Reino Unido.'),
  ('english-porter', '13C', 'English Porter', 'Brown British Beer', 1.040, 1.052, 1.008, 1.014, 18, 35, 20, 30, 4.0, 5.4, 'A moderate-strength dark brown English ale with a restrained roasty, bitter character. May have a range of roasted flavors, generally without burnt qualities, and often has a malty chocolate and caramel profile.', 'Una ale inglesa marrón oscuro, de intensidad moderada, con un discreto carácter rostizado y amargo. Puede tener una gama de sabores rostizados, generalmente sin carácter quemado, y a menudo tiene un perfil maltoso a chocolate y caramelo.'),
  ('scottish-light', '14A', 'Scottish Light', 'Scottish Ale', 1.030, 1.035, 1.010, 1.013, 10, 20, 17, 25, 2.5, 3.3, 'A low-alcohol, malty beer with light caramel, toast, toffee, and fruit flavors. A slight roast dryness offsets the residual sweetness in the finish, with the bitterness perceived only to keep the beer from being cloying.', 'Una cerveza maltosa y de bajo alcohol, con sabores ligeros a caramelo, tostadas, toffee y frutas. Una leve sequedad rostizada compensa el dulzor residual en el final, con el amargor percibido solo para evitar que la cerveza sea empalagosa.'),
  ('scottish-heavy', '14B', 'Scottish Heavy', 'Scottish Ale', 1.035, 1.040, 1.010, 1.015, 10, 20, 12, 20, 3.3, 3.9, 'A lower-alcohol, malty beer with light caramel, toast, toffee, and fruity flavors. A slight roast dryness offsets the residual sweetness in the finish, with the bitterness perceived only to keep the beer from being cloying.', 'Una cerveza maltosa y de bajo alcohol, con sabores ligeros a caramelo, tostadas, toffee y frutas. Una leve sequedad rostizada compensa el dulzor residual en el final, con el amargor percibido solo para evitar que la cerveza sea empalagosa.'),
  ('scottish-export', '14C', 'Scottish Export', 'Scottish Ale', 1.040, 1.060, 1.010, 1.016, 15, 30, 12, 20, 3.9, 6.0, 'A moderate-strength, malty beer with light caramel, toast, toffee, and fruit flavors. A slight roast dryness offsets the residual sweetness in the finish, with the bitterness perceived only to keep the beer from being cloying.', 'Una cerveza maltosa y de moderado alcohol, con sabores ligeros a caramelo, tostadas, toffee y frutas. Una leve sequedad rostizada compensa el dulzor residual en el final, con el amargor percibido solo para evitar que la cerveza sea empalagosa.'),
  ('irish-red-ale', '15A', 'Irish Red Ale', 'Irish Beer', 1.036, 1.046, 1.010, 1.014, 18, 28, 9, 14, 3.8, 5.0, 'An easy-drinking pint, often with subtle flavors. Slightly malty in the balance sometimes with an initial soft toffee or caramel sweetness, a slightly grainy biscuity palate, and a touch of roasted dryness in the finish. Some versions can emphasize the caramel and sweetness more, while others will favor the grainy palate and roasted dryness.', 'Una pinta fácil de tomar, a menudo con sabores sutiles. Ligeramente maltosa en el balance, a veces con un dulzor inicial suave a toffee o caramelo, un paladar ligeramente granoso y a galleta, y un toque de sequedad rostizada en el final. Algunas versiones pueden enfatizar más el caramelo y el dulzor, mientras que otras favorecen el paladar granoso y la sequedad rostizada.'),
  ('irish-stout', '15B', 'Irish Stout', 'Irish Beer', 1.036, 1.044, 1.007, 1.011, 25, 45, 25, 40, 3.8, 5.0, 'A black beer with a pronounced roasted flavor, often similar to coffee. The balance can range from fairly even to quite bitter, with the more balanced versions having a little malty sweetness and the bitter versions being quite dry. Draught versions typically are creamy from a nitro pour, but bottled versions will not have this dispense-derived character. The roasted flavor can range from dry and coffee-like to somewhat chocolaty.', 'Una cerveza negra con un pronunciado sabor rostizado, a menudo similar al café. El balance puede variar de bastante equilibrado a bastante amargo; las versiones más equilibradas tienen un ligero dulzor de malta y las versiones amargas son bastante secas. Las versiones tiradas (draft) suelen ser cremosas al ser servidas con nitrógeno, pero las versiones embotelladas no tendrán este carácter derivado del servicio. El sabor rostizado puede variar desde seco y similar al café hasta algo similar al chocolate.'),
  ('irish-extra-stout', '15C', 'Irish Extra Stout', 'Irish Beer', 1.052, 1.062, 1.010, 1.014, 35, 50, 30, 40, 5.0, 6.5, 'A fuller-bodied black beer with a pronounced roasted flavor, often similar to coffee and dark chocolate with some malty complexity. The balance can range from moderately bittersweet to bitter, with the more balanced versions having up to moderate malty richness and the bitter versions being quite dry.', 'Una cerveza negra de cuerpo más pleno, con un pronunciado sabor rostizado, a menudo similar al café y al chocolate amargo, con cierta complejidad de malta. El balance puede variar de moderadamente semi amargo a amargo; las versiones más balanceadas tienen una riqueza de malta de intensidad hasta moderada, y las versiones amargas son bastante secas.'),
  ('sweet-stout', '16A', 'Sweet Stout', 'Dark British Beer', 1.044, 1.060, 1.012, 1.024, 20, 40, 30, 40, 4.0, 6.0, 'A very dark, sweet, full-bodied, slightly roasty stout that can suggest coffee-and-cream, or sweetened espresso.', 'Una stout muy oscura, dulce, de cuerpo pleno, ligeramente rostizada que recuerda a café con crema o espresso endulzado.'),
  ('oatmeal-stout', '16B', 'Oatmeal Stout', 'Dark British Beer', 1.045, 1.065, 1.010, 1.018, 25, 40, 22, 40, 4.2, 5.9, 'A dark, roasty, full-bodied stout with enough sweetness to support the oat backbone. The sweetness, balance, and oatmeal impression can vary considerably.', 'Una stout oscura, rostizada, de cuerpo pleno con suficiente dulzor como para dar soporte a la base de avena. El dulzor, balance y sensación de la avena pueden variar considerablemente.'),
  ('tropical-stout', '16C', 'Tropical Stout', 'Dark British Beer', 1.056, 1.075, 1.010, 1.018, 30, 50, 30, 40, 5.5, 8.0, 'A very dark, sweet, fruity, moderately strong stout with smooth, roasty flavors, yet no burnt harshness.', 'Una stout muy oscura, dulce, afrutada y moderadamente intensa, con suaves sabores rostizados, pero sin la aspereza de sabores quemados.'),
  ('foreign-extra-stout', '16D', 'Foreign Extra Stout', 'Dark British Beer', 1.056, 1.075, 1.010, 1.018, 50, 70, 30, 40, 6.3, 8.0, 'A very dark, rich, moderately strong, fairly dry stout with prominent roast flavors.', 'Una stout muy oscura, sabrosa, moderadamente intensa, bastante seca y con sabores rostizados prominentes.'),
  ('british-strong-ale', '17A', 'British Strong Ale', 'Strong British Ale', 1.055, 1.080, 1.015, 1.022, 30, 60, 8, 22, 5.5, 8.0, 'An ale of respectable alcoholic strength, traditionally bottled-conditioned and cellared. Can have a wide range of interpretations, but most will have varying degrees of malty richness, late hops and bitterness, fruity esters, and alcohol warmth. The malt and adjunct flavors and intensity can vary widely, but any combination should result in an agreeable palate experience.', 'Una ale de respetable intensidad alcohólica, tradicionalmente acondicionada en botella y de guarda. Puede tener una amplia gama de interpretaciones, pero la mayoría tendrá diferentes niveles de riqueza de maltas, lúpulos de adición tardía y amargor, ésteres afrutados y tibieza alcohólica. Los sabores e intensidad de malta y adjuntos pueden variar ampliamente, pero cualquier combinación debe resultar en una experiencia agradable al paladar.'),
  ('old-ale', '17B', 'Old Ale', 'Strong British Ale', 1.055, 1.088, 1.015, 1.022, 30, 60, 10, 22, 5.5, 9.0, 'A stronger-than-average English ale, though usually not as strong or rich as an English Barley Wine, but usually malty. Warming. Shows positive maturation effects of a well-kept, aged beer.', 'Una ale inglesa usualmente maltosa y más fuerte que el promedio, aunque por lo general no es tan fuerte o rica como una British Barley Wine. Presenta tibieza alcohólica. Cuando está correctamente envejecida y bien cuidada, muestra los efectos positivos de la maduración.'),
  ('wee-heavy', '17C', 'Wee Heavy', 'Strong British Ale', 1.070, 1.130, 1.018, 1.040, 17, 35, 14, 25, 6.5, 10.0, 'Rich, sweet malt depth with caramel, toffee, and fruity flavors. Full-bodied and chewy, with warming alcohol. Restrained bitterness, but not cloying or syrupy.', 'Profundidad de malta rica y dulce con sabores a caramelo, toffee y frutas. De cuerpo pleno y “masticable”, con un alcohol que aporta tibieza. Amargor discreto, pero ni empalagosa ni almibarada.'),
  ('english-barley-wine', '17D', 'English Barley Wine', 'Strong British Ale', 1.080, 1.120, 1.018, 1.030, 35, 70, 8, 22, 8.0, 12.0, 'A strong and richly malty ale with a pleasant fruity or hoppy depth. A wintertime sipper with a full, chewy body and warming alcohol.', 'Una ale fuerte y ricamente maltosa, con una agradable profundidad afrutada o lupulada. Una cerveza de invierno para tomar a sorbos con tibieza alcohólica y un cuerpo pleno y “masticable”.'),
  ('blonde-ale', '18A', 'Blonde Ale', 'Pale American Ale', 1.038, 1.054, 1.008, 1.013, 15, 28, 3, 6, 3.8, 5.5, 'Easy-drinking, approachable, malt oriented American craft beer, often with interesting fruit, hop, or character malt notes. Well-balanced and clean, is a refreshing pint without aggressive flavors.', 'Una cerveza artesanal estadounidense orientada a la malta, accesible a todos los paladares y con buena tomabilidad. A menudo con interesantes notas afrutadas, a lúpulo o a maltas especiales. Limpia y bien balanceada, es una bebida refrescante sin sabores agresivos.'),
  ('american-pale-ale', '18B', 'American Pale Ale', 'Pale American Ale', 1.045, 1.060, 1.010, 1.015, 30, 50, 5, 10, 4.5, 6.2, 'An average-strength, hop-forward, pale American craft beer with sufficient supporting malt to make the beer balanced and drinkable. The clean hop presence can reflect classic or modern American or New World hop varieties with a wide range of characteristics.', 'Una cerveza artesanal estadounidense pálida, de intensidad estándar y orientada hacia el lúpulo, pero con suficiente malta de apoyo para que sea balanceada y fácil de tomar. La presencia limpia de los lúpulos puede reflejar variedades estadounidenses o del Nuevo Mundo, bien sean clásicas o modernas, con un amplio rango de características.'),
  ('american-amber-ale', '19A', 'American Amber Ale', 'Amber and Brown American Beer', 1.045, 1.060, 1.010, 1.015, 25, 40, 10, 17, 4.5, 6.2, 'An amber, hoppy, moderate-strength American craft beer with a malty caramel flavor. The balance can vary quite a bit, with some versions being fairly malty and others being aggressively hoppy. Hoppy and bitter versions should not have clashing flavors with the caramel malt profile.', 'Una cerveza artesanal estadounidense ámbar, lupulada, de moderada intensidad y con un sabor a caramelo derivado de la malta. El balance puede variar bastante, con algunas versiones siendo muy maltosas y otras agresivamente lupuladas. Las versiones lupuladas y amargas no deberían tener sabores que choquen con el perfil a caramelo de la malta.'),
  ('california-common', '19B', 'California Common', 'Amber and Brown American Beer', 1.048, 1.054, 1.011, 1.014, 30, 45, 9, 14, 4.5, 5.5, 'A toasty and caramelly, fairly bitter, standard-strength beer with an interesting fruitiness and rustic, woody hop character. Smooth and well carbonated.', 'Una cerveza tostada y acaramelada, bastante amarga, de intensidad estándar, con un interesante perfil frutal y un carácter a lúpulo como amaderado y rústico. Suave y bien carbonatada.'),
  ('american-brown-ale', '19C', 'American Brown Ale', 'Amber and Brown American Beer', 1.045, 1.060, 1.010, 1.016, 20, 30, 18, 35, 4.3, 6.2, 'A malty but hoppy standard-strength American ale frequently with chocolate and caramel flavors. The hop flavor and aroma complement and enhance the malt rather than clashing with it.', 'Una ale estadounidense maltosa pero lupulada, de intensidad estándar, frecuentemente con sabores a chocolate y caramelo. El sabor y el aroma del lúpulo complementan y realzan a la malta en lugar de chocar con ella.'),
  ('american-porter', '20A', 'American Porter', 'American Porter and Stout', 1.050, 1.070, 1.012, 1.018, 25, 50, 22, 40, 4.8, 6.5, 'A malty, bitter, and often somewhat hoppy dark beer with a balanced, roasted, and frequently chocolatey character.', 'Una cerveza oscura maltosa, amarga y a menudo un tanto lupulada, con un carácter balanceado, rostizado y frecuentemente a chocolate.'),
  ('american-stout', '20B', 'American Stout', 'American Porter and Stout', 1.050, 1.075, 1.010, 1.022, 35, 75, 30, 40, 5.0, 7.0, 'A fairly strong, highly roasted, bitter, hoppy dark stout. The body and dark flavors typical of stouts with a more aggressive American hop character and bitterness.', 'Una stout oscura bastante fuerte, altamente rostizada, amarga y lupulada. Tiene el cuerpo y los sabores oscuros típicos de una stout, con un carácter más agresivo a lúpulo estadounidense y mayor amargor.'),
  ('imperial-stout', '20C', 'Imperial Stout', 'American Porter and Stout', 1.075, 1.115, 1.018, 1.030, 50, 90, 30, 40, 8.0, 12.0, 'An intensely-flavored, very strong, very dark stout with a broad range of interpretations. Roasty-burnt malt with a depth of dark or dried fruit flavors, and a warming, bittersweet finish. Despite the intense flavors, the components need to meld together to create a complex, harmonious beer, not a hot mess -- sometimes only accomplished with age.', 'Una stout muy oscura y fuerte, de sabores intensos y con un amplio rango de interpretaciones. Malta rostizada y quemada con sabores profundos a frutas oscuras o deshidratadas, final cálido y semi amargo. A pesar de los intensos sabores, los componentes necesitan compenetrarse entre sí para crear una cerveza compleja y armoniosa, y no un auténtico desastre; a veces esto solo se logra mediante su envejecimiento.'),
  ('american-ipa', '21A', 'American IPA', 'IPA', 1.056, 1.070, 1.008, 1.014, 40, 70, 6, 14, 5.5, 7.5, 'A decidedly hoppy and bitter, moderately strong, pale American ale. The balance is hop-forward, with a clean fermentation profile, dryish finish, and clean, supporting malt allowing a creative range of hop character to shine through.', 'Una ale estadounidense pálida, decididamente lupulada y amarga, y moderadamente fuerte. El balance está orientado al lúpulo, con un perfil de fermentación limpio, un final algo seco y una malta limpia de apoyo, permitiendo que resalte una creativa gama de carácter a lúpulo.'),
  ('specialty-ipa', '21B', 'Specialty IPA', 'IPA', 1.046, 1.057, 0.990, 1.004, 20, 30, 2, 4, 6.0, 7.5, 'A very pale, hop-forward American IPA variant with a bone-dry finish, very high carbonation, and a restrained bitterness level. Can be suggestive of a sparkling white wine or Champagne. The hop character is modern, and emphasizes flavor and aroma dimensions.', 'Reconocible como una IPA por su balance (una cerveza orientada al lúpulo, amarga y algo seca) con la presencia de algo adicional para distinguirse de las categorías estándar. Debería contar con una buena tomabilidad, independientemente de cómo sea la cerveza. Una excesiva aspereza y pesadez son típicamente defectos, así como los choques de sabor fuertes entre los lúpulos y los otros ingredientes especiales.'),
  ('hazy-ipa', '21C', 'Hazy IPA', 'IPA', 1.060, 1.085, 1.010, 1.015, 25, 60, 3, 7, 6.0, 9.0, 'An American IPA with intense fruit flavors and aromas, a soft body, smooth mouthfeel, and often opaque with substantial haze. Less perceived bitterness than traditional IPAs but always massively hop-forward.', 'Una American IPA con intensos sabores y aromas a frutas, un cuerpo suave, sensación en boca sedosa, y a menudo opaca con una turbidez considerable. Con menos amargor percibido que las IPA tradicionales, pero siempre extremadamente orientada al lúpulo.'),
  ('double-ipa', '22A', 'Double IPA', 'Strong American Ale', 1.065, 1.085, 1.008, 1.018, 60, 100, 6, 14, 7.5, 10.0, 'An intensely hoppy, fairly strong, bitter pale ale without the big, rich, complex maltiness, residual sweetness, and body of an American Barleywine. Strongly hopped, but clean, dry, and lacking harshness. Despite showing its strength, drinkability is an important consideration.', 'Una ale pálida intensamente lupulada, amarga y bastante fuerte, sin la maltosidad intensa, sabrosa y compleja, el dulzor residual y el cuerpo de una American Barleywine. Fuertemente lupulada, pero limpia, seca y carente de asperezas. A pesar de exhibir su intensidad de alcohol, la tomabilidad debe ser una consideración importante.'),
  ('american-strong-ale', '22B', 'American Strong Ale', 'Strong American Ale', 1.062, 1.090, 1.014, 1.024, 50, 100, 7, 18, 6.3, 10.0, 'A malty, bitter, and strong American Ale fitting in the space between American Barleywine, Double IPA, and Red IPA. The malty and hoppy flavors can be quite strong, but are generally in balance.', 'Una ale estadounidense maltosa, amarga y fuerte, que encaja en el espacio entre las American Barleywine, Double IPA y Red IPA. Los sabores maltosos y lupulados pueden ser bastante fuertes, pero generalmente están balanceados.'),
  ('american-barleywine', '22C', 'American Barleywine', 'Strong American Ale', 1.080, 1.120, 1.016, 1.030, 50, 100, 9, 18, 8.0, 12.0, 'A very strong, malty, hoppy, bitter American ale with a rich palate, full mouthfeel, and warming aftertaste, suitable for contemplative sipping.', 'Una ale estadounidense muy fuerte, maltosa, lupulada y amarga, con un paladar rico, sensación en boca plena y un retrogusto cálido, adecuada para tomar contemplativamente a sorbos.'),
  ('wheatwine', '22D', 'Wheatwine', 'Strong American Ale', 1.080, 1.120, 1.016, 1.030, 30, 60, 6, 14, 8.0, 12.0, 'A richly textured, high alcohol sipping beer with a significant grainy, bready flavor, and a sleek body. The emphasis is first on the bready, wheaty flavors with malt, hops, fruity yeast, and alcohol complexity.', 'Una cerveza de textura exquisita, alta en alcohol, para tomar a sorbos, con un significativo sabor granoso y a pan, junto con un cuerpo sedoso. El énfasis está primero en los sabores a pan y a trigo, con la malta, los lúpulos, la levadura afrutada y el alcohol aportando complejidad.'),
  ('berliner-weisse', '23A', 'Berliner Weisse', 'European Sour Ale', 1.028, 1.032, 1.003, 1.006, 3, 8, 2, 3, 2.8, 3.8, 'A very pale, refreshing, low-alcohol German wheat beer with a clean lactic sourness and a very high carbonation level. A light bread dough malt flavor supports the sourness, which shouldn''t seem artificial. A gentle fruitiness is found in the best examples.', 'Una cerveza de trigo alemana muy pálida, refrescante y de bajo alcohol, con una acidez láctica limpia y un nivel de carbonatación muy alto. Un ligero sabor a malta como a masa de pan da soporte a la acidez, la que no debería parecer artificial. Una ligera frutosidad se puede percibir en los mejores ejemplos.'),
  ('flanders-red-ale', '23B', 'Flanders Red Ale', 'European Sour Ale', 1.048, 1.057, 1.002, 1.012, 10, 25, 10, 17, 4.6, 6.5, 'A sour and fruity oak-aged reddish-brown Belgian-style ale with supportive toasty malt flavors and fruit complexity. The dry, tannic finish supports the suggestion of a vintage red wine.', 'Una ale de estilo belga, ácida y afrutada, envejecida en roble, de color marrón rojizo, con sabores tostados de malta de apoyo y una complejidad a fruta. Un final seco y tánico sustenta la impresión de un vino tinto de guarda.'),
  ('oud-bruin', '23C', 'Oud Bruin', 'European Sour Ale', 1.040, 1.074, 1.008, 1.012, 20, 25, 17, 22, 4.0, 8.0, 'A malty, fruity, aged, somewhat sour Belgian-style brown ale with a caramel-chocolate malt flavor, and often substantial alcohol.', 'Una ale marrón de estilo belga, maltosa, afrutada, envejecida, ácida en cierta medida, con un sabor de maltas a caramelo y chocolate, y a menudo un alcohol significativo.'),
  ('lambic', '23D', 'Lambic', 'European Sour Ale', 1.040, 1.054, 1.001, 1.010, 0, 10, 3, 6, 5.0, 6.5, 'A fairly sour, often moderately funky, wild Belgian wheat beer with sourness taking the place of hop bitterness in the balance. Traditionally served uncarbonated as a café drink.', 'Una cerveza “salvaje” de trigo, originaria de Bélgica, bastante ácida, a menudo moderadamente funky, en la que la acidez reemplaza al amargor del lúpulo en el balance. Tradicionalmente servida sin carbonatación como una bebida de cafetería.'),
  ('gueuze', '23E', 'Gueuze', 'European Sour Ale', 1.040, 1.054, 1.000, 1.006, 0, 10, 5, 6, 5.0, 8.0, 'A very refreshing, highly carbonated, pleasantly sour but balanced wild Belgian wheat beer. The wild beer character can be complex and varied, combining sour, funky, and fruity flavors.', 'Una cerveza “salvaje” de trigo, de origen belga, muy refrescante, altamente carbonatada, placenteramente ácida pero balanceada. El carácter a cerveza “salvaje” puede ser complejo y variado, combinando sabores ácidos, funky y afrutados.'),
  ('fruit-lambic', '23F', 'Fruit Lambic', 'European Sour Ale', 1.040, 1.060, 1.000, 1.010, 0, 10, 3, 7, 5.0, 7.0, 'A complex, refreshing, pleasantly sour Belgian wheat beer blending a complementary fermented fruit character with a sour, funky Gueuze.', 'Una cerveza belga de trigo, compleja, refrescante y placenteramente ácida, que mezcla un carácter a fruta fermentada que se complementa con una Gueuze, ácida y funky.'),
  ('gose', '23G', 'Gose', 'European Sour Ale', 1.036, 1.056, 1.006, 1.010, 5, 12, 3, 4, 4.2, 4.8, 'A tart, lightly-bittered historical central European wheat beer with a distinctive but restrained salt and coriander character. Very refreshing, with a dry finish, high carbonation, and bright flavors.', 'Una cerveza histórica centroeuropea de trigo, de acidez ligera, levemente amarga, con un carácter distintivo pero discreto a sal y semillas de cilantro. Muy refrescante, con un final seco, alta carbonatación y sabores vivos.'),
  ('witbier', '24A', 'Witbier', 'Belgian Ale', 1.044, 1.052, 1.008, 1.012, 8, 20, 2, 4, 4.5, 5.5, 'A pale, hazy Belgian wheat beer with spices accentuating the yeast character. A delicate, lightly spiced, moderate-strength ale that is a refreshing summer drink with its high carbonation, dry finish, and light hopping.', 'Una cerveza de trigo belga pálida y turbia, con especias que acentúan el carácter de la levadura. Una ale delicada, ligeramente especiada y de intensidad moderada, que es una bebida refrescante de verano por su alta carbonatación, final seco y ligero lupulado.'),
  ('belgian-pale-ale', '24B', 'Belgian Pale Ale', 'Belgian Ale', 1.048, 1.054, 1.010, 1.014, 20, 30, 8, 14, 4.8, 5.5, 'A top-fermented, all malt, average strength Belgian ale that is moderately bitter, not dry-hopped, and without strong flavors. The copper-colored beer lacks the aggressive yeast character or sourness of many Belgian beers, but has a well-balanced, malty, fruity, and often bready and toasty profile.', 'Una ale belga de fermentación alta e intensidad media, elaborada solo con malta, moderadamente amarga, sin dry hop ni sabores fuertes. Una cerveza de color cobrizo que carece del carácter agresivo a levadura o la acidez de muchas cervezas belgas, pero que tiene un perfil bien balanceado, maltoso, afrutado y, a menudo, con carácter a pan y a tostado.'),
  ('biere-de-garde', '24C', 'Bière de Garde', 'Belgian Ale', 1.060, 1.080, 1.008, 1.016, 18, 28, 6, 19, 6.0, 8.5, 'A family of smooth, fairly strong, malty, lagered artisanal French beer with a range of malt flavors appropriate for the blond, amber, or brown color. All are malty yet dry, with clean flavors. Darker versions have more malt character, while paler versions can have more hops while still remaining malt-focused beers.', 'Una familia de cervezas artesanales francesas suaves, bastante intensas y maltosas, acondicionadas en frío, con una gama de sabores de malta apropiados para el color rubio, ámbar o marrón. Todas son maltosas pero secas, con sabores limpios. Las versiones más oscuras tienen más carácter a malta, mientras que las versiones más pálidas pueden tener más lúpulos, sin dejar de ser cervezas centradas en la malta.'),
  ('belgian-blond-ale', '25A', 'Belgian Blond Ale', 'Strong Belgian Ale', 1.062, 1.075, 1.008, 1.018, 15, 30, 4, 6, 6.0, 7.5, 'A golden, moderately-strong Belgian ale with a pleasantly subtle citrusy-spicy yeast complexity, smooth malty palate, and dry, soft finish.', 'Una ale belga dorada, moderadamente alcohólica con una agradable y sutil complejidad de levadura con carácter cítrico y especiado, paladar maltoso sedoso y un final seco y suave.'),
  ('saison', '25B', 'Saison', 'Strong Belgian Ale', 1.048, 1.065, 1.002, 1.008, 20, 35, 5, 22, 3.5, 9.5, 'A family of refreshing, highly attenuated, hoppy, and fairly bitter Belgian ales with a very dry finish and high carbonation. Characterized by a fruity, spicy, sometimes phenolic fermentation profile, and the use of cereal grains and sometimes spices for complexity. Several variations in strength and color exist.', 'Una familia de ales belgas refrescantes, altamente atenuadas, lupuladas y bastante amargas, con un final muy seco y alta carbonatación. Caracterizadas por un perfil de fermentación afrutado, especiado y algunas veces fenólico, el uso de cereales y a veces especias para aportar complejidad. Existe una amplia variedad en cuanto a intensidad alcohólica y color.'),
  ('belgian-golden-strong-ale', '25C', 'Belgian Golden Strong Ale', 'Strong Belgian Ale', 1.070, 1.095, 1.005, 1.016, 22, 35, 3, 6, 7.5, 10.5, 'A very pale, highly attenuated, strong Belgian ale that is more fruity and hoppy than spicy. Complex and delicate, the dry finish, light body, and high carbonation accentuate the yeast and hop character. Sparkling carbonation and effervescent, forming a rocky white head.', 'Una ale belga muy pálida, altamente atenuada y fuerte, que es más afrutada y lupulada que especiada. Compleja y delicada, con un final seco, cuerpo ligero y alta carbonatación que acentúan el carácter a levadura y lúpulo. Carbonatación burbujeante y efervescente, formando una espuma blanca “rocosa”.'),
  ('belgian-single', '26A', 'Belgian Single', 'Monastic Ale', 1.044, 1.054, 1.004, 1.010, 25, 45, 3, 5, 4.8, 6.0, 'A blond, bitter, hoppy table beer that is very dry and highly carbonated. The aggressive fruity-spicy Belgian yeast character and high bitterness is forward in the balance, with a soft, supportive grainy-sweet malt palate, and a spicy-floral hop profile.', 'Una cerveza de mesa rubia, amarga y lupulada, muy seca y altamente carbonatada. El agresivo carácter de la levadura belga, afrutado y especiado, junto con el alto amargor predominan en el balance, con un suave paladar de malta a grano dulce de soporte, y un perfil de lúpulo especiado y floral.'),
  ('belgian-dubbel', '26B', 'Belgian Dubbel', 'Monastic Ale', 1.062, 1.075, 1.008, 1.018, 15, 25, 10, 17, 6.0, 7.6, 'A deep reddish-copper, moderately strong, malty, complex Belgian ale with rich malty flavors, dark or dried fruit esters, and light alcohol blended together in a malty presentation that still finishes fairly dry.', 'Una ale belga de color rojo cobrizo profundo, moderadamente fuerte, maltosa y compleja, con ricos sabores a malta, ésteres de frutas oscuras o deshidratadas y un alcohol ligero, todo mezclado en una presentación que, aunque maltosa, tiene un final bastante seco.'),
  ('belgian-tripel', '26C', 'Belgian Tripel', 'Monastic Ale', 1.075, 1.085, 1.008, 1.014, 20, 40, 4.5, 7, 7.5, 9.5, 'A strong, pale, somewhat spicy Belgian ale with a pleasant rounded malt flavor, firm bitterness, and dry finish. Quite aromatic, with spicy, fruity, and light alcohol notes combining with the supportive clean malt character to produce a surprisingly drinkable beverage considering the high alcohol content.', 'Una ale belga fuerte, pálida y en cierta medida especiada, con un sabor a malta agradable y redondo, amargor firme y final seco. Bastante aromática, con notas especiadas, afrutadas y a ligero alcohol, combinadas con un carácter limpio a malta de soporte, para producir una bebida con una sorprendente tomabilidad considerando su alto contenido de alcohol.'),
  ('belgian-dark-strong-ale', '26D', 'Belgian Dark Strong Ale', 'Monastic Ale', 1.075, 1.110, 1.010, 1.024, 20, 35, 12, 22, 8.0, 12.0, 'A dark, complex, very strong Belgian ale with a delicious blend of malt richness, dark fruit flavors, and spicy notes. Complex, rich, smooth, and dangerous.', 'Una ale belga oscura, compleja y muy fuerte, con una deliciosa combinación de riqueza de malta, sabores a frutas oscuras y notas especiadas. Compleja, rica, suave y peligrosa.'),
  ('historical-beer-kentucky-common', '27B', 'Historical Beer: Kentucky Common', 'Historical Beer', 1.044, 1.055, 1.010, 1.018, 15, 30, 11, 20, 4.0, 5.5, 'A clean, dry, refreshing, slightly malty dark beer with high carbonation. Mild-tasting, with light toast and caramel flavors, served very fresh as a sessionable saloon beer.', 'Una cerveza oscura limpia, seca y refrescante, levemente maltosa y con alta carbonatación. De sabor suave, con ligero carácter a tostadas y caramelo, era servida muy fresca en cantinas como cerveza de sesión.'),
  ('historical-beer-lichtenhainer', '27C', 'Historical Beer: Lichtenhainer', 'Historical Beer', 1.032, 1.040, 1.004, 1.008, 5, 12, 3, 6, 3.5, 4.7, 'A sour, smoked, lower-gravity historical central European wheat beer. Complex yet refreshing character due to high attenuation and carbonation, along with low bitterness and moderate sourness.', 'Una cerveza de trigo histórica de Europa central, ácida, ahumada y de baja densidad. De carácter complejo pero refrescante debido a una alta atenuación y carbonatación, junto con un amargor bajo y acidez moderada.'),
  ('historical-beer-london-brown-ale', '27D', 'Historical Beer: London Brown Ale', 'Historical Beer', 1.033, 1.038, 1.012, 1.015, 15, 20, 22, 35, 2.8, 3.6, 'A luscious, sweet, malty, low-alcohol dark brown ale, with caramel and toffee malt complexity and a sweet-tasting finish.', 'Una ale marrón oscura baja en alcohol, maltosa, dulce y exquisita, exhibiendo una complejidad de malta a caramelo y toffee junto con un final de sabor dulce.'),
  ('historical-beer-piwo-grodziskie', '27E', 'Historical Beer: Piwo Grodziskie', 'Historical Beer', 1.028, 1.032, 1.006, 1.012, 20, 35, 3, 6, 2.5, 3.3, 'A low-gravity, bitter, oak-smoked historical central European wheat beer with a clean fermentation profile and no sourness. Highly carbonated, dry, crisp, and refreshing.', 'Una cerveza histórica de trigo de Europa central, ahumada con roble, amarga y de densidad baja, con un perfil de fermentación limpio y sin acidez. Altamente carbonatada, seca, crisp y refrescante.'),
  ('historical-beer-pre-prohibition-lager', '27F', 'Historical Beer: Pre-Prohibition Lager', 'Historical Beer', 1.044, 1.060, 1.010, 1.015, 25, 40, 3, 6, 4.5, 6.0, 'A bitter and hoppy pale American adjunct lager, often with a robust, corny flavor profile, although more crisp and neutral-tasting versions exist.', 'Una lager pálida estadounidense con adjuntos, amarga y lupulada, a menudo con un perfil de sabor robusto y a maíz, aunque existen versiones más crisp y de sabor neutro.'),
  ('historical-beer-pre-prohibition-porter', '27G', 'Historical Beer: Pre-Prohibition Porter', 'Historical Beer', 1.046, 1.060, 1.010, 1.016, 20, 30, 20, 30, 4.5, 6.0, 'A historical American adaptation of English Porter by German immigrants using American ingredients, including adjuncts.', 'Una adaptación histórica estadounidense de la English Porter, desarrollada por inmigrantes provenientes de Alemania, que utiliza ingredientes estadounidenses, incluyendo adjuntos.'),
  ('historical-beer-roggenbier', '27H', 'Historical Beer: Roggenbier', 'Historical Beer', 1.046, 1.056, 1.010, 1.014, 10, 20, 14, 19, 4.5, 6.0, 'A Dunkles Weissbier made with rye rather than wheat, but with a greater body and light finishing hops. The rye gives a bready and peppery flavor, a creamy body, and a dry, grainy finish that blends with the distinctive banana-and-clove weizen yeast character.', 'Una Dunkles Weissbier elaborada con centeno en vez de trigo, pero con mayor cuerpo y ligeros lúpulos de adición tardía. El centeno aporta un sabor a pan y a pimienta, un cuerpo cremoso, y un final seco y granoso que se mezcla con el carácter distintivo a banana/plátano y clavo de olor de la levadura Weizen.'),
  ('historical-beer-sahti', '27I', 'Historical Beer: Sahti', 'Historical Beer', 1.076, 1.120, 1.016, 1.038, 0, 15, 4, 22, 7.0, 11.0, 'A sweet, heavy, strong traditional Finnish farmhouse beer usually with rye and juniper, and a banana-clove yeast character.', 'Una cerveza de elaboración tradicional en granjas (farmhouse) de Finlandia, dulce, pesada y fuerte, usualmente con centeno y enebro, y un carácter de levadura a banana/plátano y clavo de olor.'),
  ('straight-sour-beer', '28D', 'Straight Sour Beer', 'American Wild Ale', 1.048, 1.065, 1.006, 1.013, 3, 8, 2, 3, 4.5, 7.0, 'A pale, refreshing, sour beer with a clean lactic sourness. A gentle, pale malt flavor supports the lemony sourness with moderate fruity esters.', 'Una cerveza pálida, ácida y refrescante, con una acidez láctica limpia. Un suave sabor a malta pálida apoya la acidez a limón con moderados ésteres afrutados.'),
  ('grape-ale', '29D', 'Grape Ale', 'Fruit Beer', 1.059, 1.075, 1.004, 1.013, 10, 30, 4, 8, 6.0, 8.5, 'Combines the profile of a sparkling wine and a relatively neutral base beer allowing the aromatic qualities of the grape to blend pleasantly with hop and yeast aromatics. Can be in a range from refreshing to complex.', 'Combina el perfil de un vino espumoso y una cerveza de base relativamente neutra, que permite que las cualidades aromáticas de la uva se mezclen agradablemente con los aromas del lúpulo y la levadura. Puede estar en un rango de refrescante a compleja.'),
  ('common-cider-2025', 'C1A', 'Common Cider', 'Traditional Cider', 1.045, 1.065, 0.995, 1.020, NULL, NULL, NULL, NULL, 4.5, 8, 'A refreshing drink with the fruity and floral aroma of apples and a bright, juicy acidity. Fresh, with a clean fermentation, but possibly showing a slight yeast character.', 'Una bebida refrescante con el aroma frutal y floral de las manzanas, y una acidez brillante y jugosa. Fresca, de fermentación limpia, aunque puede mostrar un leve carácter a levadura.'),
  ('heirloom-cider-2025', 'C1B', 'Heirloom Cider', 'Traditional Cider', 1.050, 1.080, 0.995, 1.020, NULL, NULL, NULL, NULL, 6, 9, 'Combining the apple character and acidity of a Common Cider with the tannin of an English or French Cider, while retaining a clean fermentation profile.', 'Combina el carácter de la manzana y la acidez de una sidra común con los taninos de una sidra inglesa o francesa, manteniendo un perfil de fermentación limpio.'),
  ('english-cider-2025', 'C1C', 'English Cider', 'Traditional Cider', 1.050, 1.075, 0.995, 1.015, NULL, NULL, NULL, NULL, 6, 9, 'Full-bodied and often seeming quite dry, with a complex flavor and aroma. The apple character is generally subtle, with the balance dominated by tannin and fermentation-derived notes.', 'Con un cuerpo pleno, frecuentemente se percibe como bastante seca y con un final largo debido al alto contenido de taninos. La expresión de la fruta puede parecer sutil debido a un menor carácter a ésteres de manzana, en comparación con la mayoría de los demás estilos. El perfil de sabor derivado de la fruta puede ser complejo, pero no afrutado. Opcionalmente, puede tener una complejidad fenólica, ahumada o ligeramente a establo producto de la FML.'),
  ('french-cider-2025', 'C1D', 'French Cider', 'Traditional Cider', 1.045, 1.065, 1.005, 1.020, NULL, NULL, NULL, NULL, 3, 6, 'Medium to sweet, full-bodied, rich. The apple character is prominent, complemented by restrained tannin and acidity, and a clean fermentation profile.', 'Cuerpo pleno y rico, con nivel de dulzor de medio a dulce. Algo afrutada. Puede presentar un carácter fenólico, ahumado o a granja en segundo plano.'),
  ('spanish-cider-2025', 'C1E', 'Spanish Cider', 'Traditional Cider', 1.040, 1.055, 0.995, 1.010, NULL, NULL, NULL, NULL, 5, 6.5, 'Dry and fresh, with a bright acidity that may contain light to moderate acetic and wild notes. Rustic and earthy impression, traditionally unfiltered.', 'Seca y fresca, con una acidez brillante que puede contener notas acéticas y salvajes de ligeras a moderadas. De impresión rústica y terrosa, tradicionalmente es un producto sin filtrar.'),
  ('new-england-cider-2025', 'C2A', 'New England Cider', 'Strong Cider', 1.060, 1.100, 0.995, 1.020, NULL, NULL, NULL, NULL, 7, 13, 'Substantial body and character. Typically relatively dry, but can be somewhat sweet if balanced and without hot alcohol. Sometimes has barrel character and flavors from adjuncts, especially raisins.', 'Cuerpo y carácter considerables. Por lo general es relativamente seca, pero puede ser algo dulce si está balanceada y no contiene un nivel de alcohol excesivo. A veces presenta carácter a barrica. A menudo tiene sabores provenientes de los adjuntos, especialmente a uvas pasas.'),
  ('applewine-2025', 'C2B', 'Applewine', 'Strong Cider', 1.070, 1.100, 0.995, 1.020, NULL, NULL, NULL, NULL, 9, 12, 'Typically presents like a dry white wine, with fruity and floral notes. Balanced, with low astringency and bitterness, and a clean alcohol character.', 'Generalmente se presenta como un vino blanco seco, con notas frutales y florales. Balanceada, con baja astringencia y amargor. El alcohol suele ser perceptible.'),
  ('ice-cider-2025', 'C2C', 'Ice Cider', 'Strong Cider', 1.130, 1.180, 1.050, 1.085, NULL, NULL, NULL, NULL, 7, 13, 'Fruity, with depth and complexity of apple flavor. Smooth, rich, sweet, and dessert-wine-like, with enough acidity to remain balanced and bright.', 'Frutal, con profundidad y complejidad de sabor a manzana. Suave, rica, dulce y similar a un vino de postre, con una acidez suficiente para mantenerla balanceada y brillante.'),
  ('fire-cider-2025', 'C2D', 'Fire Cider', 'Strong Cider', 1.130, 1.180, 1.040, 1.075, NULL, NULL, NULL, NULL, 9, 16, 'A dark gold to brown cider with a very sweet, caramelized, maple sugar-like impression. Well-aged versions often exhibit a dark fruit or sherry-like character.', 'Una sidra cuyo color va de dorado oscuro a marrón, con una impresión muy dulce, caramelizada, similar al azúcar de arce. Las versiones correctamente envejecidas suelen presentar un carácter a frutas oscuras o similar al jerez.'),
  ('fruit-cider-2025', 'C3A', 'Fruit Cider', 'Specialty Cider', 1.045, 1.070, 0.995, 1.010, NULL, NULL, NULL, NULL, 5, 9, 'A pleasant integration of cider and added fruit. The apple character and the added fruit must be noticeable, balanced, and complementary.', 'Una integración placentera entre la sidra y la fruta añadida. El carácter de la manzana y la fruta añadida deben ser perceptibles, balanceados y complementarios. Si se declara un estilo base, debe mostrar alguna característica del mismo. Si no se declara un estilo base, se debe asumir como una sidra común.'),
  ('spiced-cider-2025', 'C3B', 'Spiced Cider', 'Specialty Cider', 1.045, 1.070, 0.995, 1.010, NULL, NULL, NULL, NULL, 5, 9, 'A pleasant integration of cider and added spices. The apple character and declared spices must be noticeable, balanced, and complementary.', 'Una integración placentera entre la sidra y las especias añadidas. El carácter de la manzana debe combinarse con los botánicos para producir un resultado balanceado. Si se declara un estilo base, debe mostrar alguna característica del mismo.'),
  ('experimental-cider-2025', 'C3C', 'Experimental Cider', 'Specialty Cider', 1.045, 1.100, 0.995, 1.020, NULL, NULL, NULL, NULL, 5, 12, 'An open-ended cider with ingredients or processes not covered by other styles. Cider character must remain recognizable, with balanced experimental components and good drinkability.', 'Una sidra abierta a ingredientes o procesos no cubiertos por otros estilos. El carácter de sidra debe seguir siendo reconocible, con componentes experimentales balanceados y buena tomabilidad.'),
  ('common-perry-2025', 'C4A', 'Common Perry', 'Perry', 1.050, 1.060, 1.000, 1.020, NULL, NULL, NULL, NULL, 5, 8, 'Mildly fruity and fuller-bodied. Usually semi-dry to semi-sweet, and typically still to pétillant. Only very slight acetification is acceptable.', 'Ligeramente afrutada, de cuerpo pleno. Generalmente de semiseca a semidulce. Usualmente de tranquila a burbujeante. Solo se acepta una acetificación muy leve.'),
  ('heirloom-perry-2025', 'C4B', 'Heirloom Perry', 'Perry', 1.050, 1.070, 1.000, 1.020, NULL, NULL, NULL, NULL, 4, 9, 'Tannic and somewhat fruity, with a fuller body. Pear character, acidity, tannin, and sweetness combine into a structured and refreshing perry.', 'Tánica y ligeramente afrutada, con un cuerpo pleno. Los ejemplos ingleses tienden a ser más secos que los franceses, por lo que el nivel de dulzor es variable. Tanto los ejemplos ingleses como los franceses pueden tener una carbonatación bastante alta.'),
  ('ice-perry-2025', 'C4C', 'Ice Perry', 'Perry', 1.130, 1.170, 1.050, 1.085, NULL, NULL, NULL, NULL, 9, 12, 'Full-bodied, bright, and fruity, with a rich pear character. Sweet and dessert-wine-like, with balancing acidity that prevents a cloying finish.', 'Cuerpo pleno, brillante y frutal, con una acidez balanceada. Dulce, pero no empalagosa. De tranquila hasta burbujeante.'),
  ('experimental-perry-2025', 'C4D', 'Experimental Perry', 'Perry', 1.045, 1.100, 0.995, 1.020, NULL, NULL, NULL, NULL, 5, 12, 'An open-ended perry with ingredients or processes not covered by other styles. Perry character must remain recognizable, with balanced experimental components and good drinkability.', 'Una perada abierta a ingredientes o procesos no cubiertos por otros estilos. El carácter de perada debe seguir siendo reconocible, con componentes experimentales balanceados y buena tomabilidad.')
